// topic: eyesafeu/worker/W001/vitals
// payload: { heartRate: 75, temperature: 36.5 }

const topicParts = msg.topic.split('/');
const workerId = topicParts[2];

msg.payload = {
    id: workerId,
    heartRate: msg.payload.heartRate || msg.payload.heart_rate,
    temperature: msg.payload.temperature || msg.payload.body_temp
};

// حفظ للـ Supabase
msg.supabaseTable = 'vital_signs';
msg.supabaseRow = {
    worker_id: workerId,
    heart_rate: msg.payload.heartRate,
    body_temp: msg.payload.temperature
};

return msg;

// topic: eyesafeu/worker/W001/state
// payload: { state: 'SOS' | 'Fall Detected' | 'Normal' }

const topicParts = msg.topic.split('/');
const workerId = topicParts[2];

msg.payload = {
    id: workerId,
    state: msg.payload.state || msg.payload.status
};

// لو SOS أو Fall → سجّل في incidents
if (msg.payload.state === 'SOS' || msg.payload.state === 'Fall Detected') {
    msg.supabaseTable = 'incidents';
    msg.supabaseRow = {
        worker_id: workerId,
        incident_type: msg.payload.state === 'SOS' ? 'SOS' : 'Fall',
        severity: 'Critical',
        description: msg.payload.state === 'SOS'
            ? 'SOS Button Pressed'
            : 'Fall Detected - immediate attention required'
    };
    const incidentMsg = { ...msg };
    node.send([msg, incidentMsg]);
} else {
    node.send([msg, null]);
}

// topic: eyesafeu/worker/W001/zone
// payload: { zone: 'Assembly Area', inZone: true }

const topicParts = msg.topic.split('/');
const workerId = topicParts[2];

msg.payload = {
    id: workerId,
    zone: msg.payload.zone || msg.payload.current_zone,
    inZone: msg.payload.inZone !== undefined ? msg.payload.inZone : msg.payload.is_inside_zone === 1
};

msg.supabaseTable = 'zone_activity_logs';
msg.supabaseRow = {
    worker_id: workerId,
    current_zone: msg.payload.zone,
    is_inside_zone: msg.payload.inZone ? 1 : 0
};

return msg;

